// Verify /api/directions returns 400 for non-numeric params — schema or handler catches it
async function testDirectionsNonNumericParams() {
  const res = await fetch('http://localhost:3001/api/directions?lat=abc&lon=def');
  assertEquals(res.status, 400);
  const body = await res.json();
  // Either schema validation or handler validation will reject this
  assert(body.error, 'Should have an error field');
}
